/**
 * @brief Return the pre-baked 1-bit bitmap for an OWM icon code.
 * @param icon_code  OWM icon string, e.g. "01d", "10n"
 * @return Pointer to WEATHER_ICON_BYTES bytes, or NULL if unknown.
 */
static inline const uint8_t *weather_icon_bitmap(const char *icon_code) {
    if (!icon_code || icon_code[0] == '\0')
        return NULL;
    if (strcmp(icon_code, "01d") == 0)
        return icon_01d;
    if (strcmp(icon_code, "01n") == 0)
        return icon_01n;
    if (strcmp(icon_code, "02d") == 0)
        return icon_02d;
    if (strcmp(icon_code, "02n") == 0)
        return icon_02n;
    if (strcmp(icon_code, "03d") == 0)
        return icon_03d;
    if (strcmp(icon_code, "03n") == 0)
        return icon_03n;
    if (strcmp(icon_code, "04d") == 0)
        return icon_04d;
    if (strcmp(icon_code, "04n") == 0)
        return icon_04n;
    if (strcmp(icon_code, "09d") == 0)
        return icon_09d;
    if (strcmp(icon_code, "09n") == 0)
        return icon_09n;
    if (strcmp(icon_code, "10d") == 0)
        return icon_10d;
    if (strcmp(icon_code, "10n") == 0)
        return icon_10n;
    if (strcmp(icon_code, "11d") == 0)
        return icon_11d;
    if (strcmp(icon_code, "11n") == 0)
        return icon_11n;
    if (strcmp(icon_code, "13d") == 0)
        return icon_13d;
    if (strcmp(icon_code, "13n") == 0)
        return icon_13n;
    if (strcmp(icon_code, "50d") == 0)
        return icon_50d;
    if (strcmp(icon_code, "50n") == 0)
        return icon_50n;
    return NULL;
}

